class Solution:
    def distanceTraveled(self, mainTank: int, additionalTank: int) -> int:
        total_fuel = mainTank
        distance = 0
        while total_fuel > 0:
            if total_fuel >= 5 and additionalTank > 0:
                total_fuel -= 4
                additionalTank -= 1
            else:
                total_fuel -= 1
            distance += 10 * min(total_fuel, 1)
        return distance

